/* ============================================================
   Imelda's Sweet Event — logique du site
   Persistance : window.storage (fourni par l'environnement Artifact)
   ⚠️ Prototype fonctionnel : en production WordPress, remplacer
   window.storage par de vraies requêtes vers votre backend/BDD,
   avec mots de passe hashés côté serveur.
   ============================================================ */

/* ============================================================
   PRÉCHARGEUR — verrouille le scroll pendant l'animation
   ============================================================ */
document.body.classList.add('pl-locked');
const __plStart = Date.now();
function hidePreloader(){
  const pl = document.getElementById('preloader');
  if(!pl || pl.dataset.hidden) return;
  pl.dataset.hidden = '1';
  const MIN_DISPLAY = 2200; // durée minimale pour laisser l'animation se jouer
  const elapsed = Date.now() - __plStart;
  const wait = Math.max(0, MIN_DISPLAY - elapsed);
  setTimeout(()=>{
    pl.classList.add('pl-hide');
    document.body.classList.remove('pl-locked');
    document.body.classList.add('pl-reveal');
    setTimeout(()=>{ pl.remove(); }, 900);
  }, wait);
}

// Filet de sécurité : si une erreur bloque l'initialisation, le préchargeur
// disparaît quand même après 6s pour ne jamais bloquer l'accès au site.
setTimeout(hidePreloader, 6000);

/* ============================================================
   POLYFILL DE STOCKAGE — indispensable pour un site en ligne
   window.storage n'existe que dans l'aperçu Claude. Une fois le
   site déployé sur un vrai hébergement, ce polyfill prend le relai
   automatiquement en utilisant localStorage du navigateur, pour que
   panier, connexion, actualités, etc. continuent de fonctionner.
   ⚠️ Limite importante : localStorage est propre à chaque navigateur/
   appareil. Pour que TOUS les visiteurs voient les mêmes commandes,
   utilisateurs et actualités (au lieu d'une copie par appareil), il
   faudra brancher un vrai backend (base de données) — voir la note
   fournie séparément.
   ============================================================ */
if(!window.storage){
  window.storage = {
    async get(key, shared){
      const raw = localStorage.getItem('ise_ls_'+key);
      if(raw === null) return null;
      return {key, value: raw, shared: !!shared};
    },
    async set(key, value, shared){
      localStorage.setItem('ise_ls_'+key, value);
      return {key, value, shared: !!shared};
    },
    async delete(key, shared){
      localStorage.removeItem('ise_ls_'+key);
      return {key, deleted:true, shared: !!shared};
    },
    async list(prefix, shared){
      const keys = [];
      const p = 'ise_ls_'+(prefix||'');
      for(let i=0;i<localStorage.length;i++){
        const k = localStorage.key(i);
        if(k && k.startsWith(p)) keys.push(k.replace('ise_ls_',''));
      }
      return {keys, prefix, shared: !!shared};
    }
  };
}

