/* ---------------- STORAGE HELPERS ---------------- */
async function loadAll(){
  try{ const r = await window.storage.get('ise_users', true); state.users = r ? JSON.parse(r.value) : []; }catch(e){ state.users = []; }
  try{ const r = await window.storage.get('ise_posts', true); state.posts = r ? JSON.parse(r.value) : []; }catch(e){ state.posts = []; }
  try{ const r = await window.storage.get('ise_orders', true); state.orders = r ? JSON.parse(r.value) : []; }catch(e){ state.orders = []; }
  const defaultSite = JSON.parse(JSON.stringify(state.site)); // snapshot des valeurs par défaut définies plus haut
  try{
    const r = await window.storage.get('ise_site', true);
    if(r){
      const loaded = JSON.parse(r.value);
      state.site = {
        ...defaultSite, ...loaded,
        images: { ...defaultSite.images, ...(loaded.images||{}) },
        colors: { ...defaultSite.colors, ...(loaded.colors||{}) },
        hero: { ...defaultSite.hero, ...(loaded.hero||{}) },
        products: (loaded.products && loaded.products.length) ? loaded.products : defaultSite.products,
        gallery: (loaded.gallery && loaded.gallery.length) ? loaded.gallery : defaultSite.gallery,
        testimonials: (loaded.testimonials && loaded.testimonials.length) ? loaded.testimonials : defaultSite.testimonials
      };
    }
  }catch(e){ /* keep defaults */ }

  // Seed default admin + sample posts on first run
  let changed = false;
  if(state.users.length === 0){
    state.users.push({username:"admin", email:"admin@imeldasweetevent.com", password:"admin123", role:"admin", createdAt:Date.now(), lastActive:Date.now()});
    changed = true;
  }
  if(state.posts.length === 0){
    state.posts.push(
      {id:cryptoId(), title:"Notre nouvelle collection de gâteaux de mariage 2026", body:"Découvrez trois nouveaux designs inspirés des tons pastel et du dégradé floral, disponibles dès ce mois-ci sur commande.", media:"image", author:"admin", date:Date.now()-86400000*2, likes:[], comments:[]},
      {id:cryptoId(), title:"Vidéo des coulisses : montage d'une pièce montée", body:"Un aperçu du travail minutieux derrière chaque étage — du glaçage à la décoration finale.", media:"video", author:"admin", date:Date.now()-86400000, likes:[], comments:[]}
    );
    changed = true;
  }
  if(changed) await persistUsers(), await persistPosts();
  await persistSiteIfMissing();
}

async function persistUsers(){ try{ await window.storage.set('ise_users', JSON.stringify(state.users), true); }catch(e){ console.error(e); } }
async function persistPosts(){ try{ await window.storage.set('ise_posts', JSON.stringify(state.posts), true); }catch(e){ console.error(e); } }
async function persistOrders(){ try{ await window.storage.set('ise_orders', JSON.stringify(state.orders), true); }catch(e){ console.error(e); } }
async function persistSite(){ try{ await window.storage.set('ise_site', JSON.stringify(state.site), true); }catch(e){ console.error(e); } }
async function persistSiteIfMissing(){
  try{ const r = await window.storage.get('ise_site', true); if(!r) await persistSite(); }catch(e){ await persistSite(); }
}
async function saveSession(username){ try{ await window.storage.set('ise_session', JSON.stringify({username}), false); }catch(e){} }
async function clearSession(){ try{ await window.storage.delete('ise_session', false); }catch(e){} }
async function loadSession(){ try{ const r = await window.storage.get('ise_session', false); return r ? JSON.parse(r.value) : null; }catch(e){ return null; } }

function cryptoId(){ return Date.now().toString(36) + Math.random().toString(36).slice(2,8); }
function fileToDataURL(file){
  return new Promise((resolve, reject)=>{
    const reader = new FileReader();
    reader.onload = ()=>resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

/* ---------------- NAVIGATION ---------------- */
function goTo(page){
  if(page === 'dashboard' && !(state.currentUser && state.currentUser.role === 'admin')){ return; }
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  const target = document.getElementById('page-'+page);
  if(target) target.classList.add('active');
  document.querySelectorAll('.nav-links button').forEach(b=>b.classList.remove('active'));
  const navBtn = document.querySelector('.nav-links button[data-page="'+page+'"]');
  if(navBtn) navBtn.classList.add('active');
  window.scrollTo({top:0, behavior:'smooth'});
  const navLinks = document.getElementById('navLinks');
  if(window.innerWidth <= 900) navLinks.style.display = 'none';
  if(page === 'dashboard') renderDashboard();
  initScrollReveal();
}
document.addEventListener('click', (e)=>{
  const t = e.target.closest('[data-goto]');
  if(t) goTo(t.dataset.goto);
});
document.querySelectorAll('.nav-links button[data-page]').forEach(btn=>{
  btn.addEventListener('click', ()=>goTo(btn.dataset.page));
});
document.getElementById('burger').addEventListener('click', ()=>{
  const nav = document.getElementById('navLinks');
  const isOpen = nav.style.display === 'flex';
  if(isOpen){ nav.style.display='none'; }
  else{
    nav.style.display='flex'; nav.style.position='absolute'; nav.style.top='64px'; nav.style.left='0'; nav.style.right='0';
    nav.style.background='var(--canvas)'; nav.style.flexDirection='column'; nav.style.padding='12px 24px'; nav.style.boxShadow='var(--shadow)';
  }
});

/* ---------------- AUTH UI ---------------- */
function renderAuthArea(){
  const area = document.getElementById('authArea');
  if(state.currentUser){
    const u = state.currentUser;
    area.innerHTML = `
      <div class="account-menu">
        <button class="account-btn" id="accountBtn"><span class="avatar-circle">${u.username[0].toUpperCase()}</span> ${u.username}</button>
        <div class="account-dropdown" id="accountDropdown">
          ${u.role==='admin' ? '<button id="gotoDashBtn">📊 Tableau de bord</button>' : ''}
          <button id="logoutBtn">↩ Déconnexion</button>
        </div>
      </div>`;
    document.getElementById('accountBtn').addEventListener('click', ()=>{
      document.getElementById('accountDropdown').classList.toggle('open');
    });
    if(u.role==='admin') document.getElementById('gotoDashBtn').addEventListener('click', ()=>goTo('dashboard'));
    document.getElementById('logoutBtn').addEventListener('click', logout);
  } else {
    area.innerHTML = `<button class="login-trigger-btn" id="openAuthBtn">Connexion</button>`;
    document.getElementById('openAuthBtn').addEventListener('click', ()=>openAuthModal('login'));
  }
  document.getElementById('newsComposer').style.display = (state.currentUser && state.currentUser.role==='admin') ? 'block' : 'none';
  document.getElementById('newsLoginHint').style.display = state.currentUser ? 'none' : 'inline';
}
document.addEventListener('click', (e)=>{
  if(!e.target.closest('.account-menu')){ const d=document.getElementById('accountDropdown'); if(d) d.classList.remove('open'); }
});

function openAuthModal(tab){
  document.getElementById('authModal').classList.add('open');
  switchAuthTab(tab);
}
document.getElementById('closeAuthModal').addEventListener('click', ()=>document.getElementById('authModal').classList.remove('open'));
document.querySelectorAll('.auth-tab').forEach(t=>t.addEventListener('click', ()=>switchAuthTab(t.dataset.auth)));
function switchAuthTab(tab){
  document.querySelectorAll('.auth-tab').forEach(t=>t.classList.toggle('active', t.dataset.auth===tab));
  document.getElementById('loginForm').style.display = tab==='login' ? 'block':'none';
  document.getElementById('registerForm').style.display = tab==='register' ? 'block':'none';
}

document.getElementById('loginForm').addEventListener('submit', async (e)=>{
  e.preventDefault();
  const username = document.getElementById('loginUsername').value.trim();
  const password = document.getElementById('loginPassword').value;
  const user = state.users.find(u=>u.username.toLowerCase()===username.toLowerCase() && u.password===password);
  if(!user){ document.getElementById('loginError').textContent = "Identifiants incorrects."; return; }
  await login(user);
  document.getElementById('authModal').classList.remove('open');
  e.target.reset();
});

document.getElementById('registerForm').addEventListener('submit', async (e)=>{
  e.preventDefault();
  const username = document.getElementById('regUsername').value.trim();
  const email = document.getElementById('regEmail').value.trim();
  const password = document.getElementById('regPassword').value;
  if(state.users.some(u=>u.username.toLowerCase()===username.toLowerCase())){
    document.getElementById('registerError').textContent = "Ce nom d'utilisateur est déjà pris.";
    return;
  }
  const newUser = {username, email, password, role:"client", createdAt:Date.now(), lastActive:Date.now()};
  state.users.push(newUser);
  await persistUsers();
  await login(newUser);
  document.getElementById('authModal').classList.remove('open');
  e.target.reset();
});

async function login(user){
  state.currentUser = {username:user.username, email:user.email, role:user.role};
  user.lastActive = Date.now();
  await persistUsers();
  await saveSession(user.username);
  renderAuthArea();
  renderNewsFeed();
}
async function logout(){
  state.currentUser = null;
  await clearSession();
  renderAuthArea();
  renderNewsFeed();
  goTo('home');
}

/* ---------------- NEWS FEED ---------------- */
document.getElementById('publishPostBtn').addEventListener('click', async ()=>{
  const title = document.getElementById('newPostTitle').value.trim();
  const body = document.getElementById('newPostBody').value.trim();
  const media = document.getElementById('newPostMedia').value;
  if(!title || !body) return;
  state.posts.unshift({id:cryptoId(), title, body, media, author:state.currentUser.username, date:Date.now(), likes:[], comments:[]});
  await persistPosts();
  document.getElementById('newPostTitle').value=''; document.getElementById('newPostBody').value='';
  renderNewsFeed();
});

function timeAgo(ts){
  const diff = Date.now()-ts;
  const mins = Math.floor(diff/60000);
  if(mins < 60) return mins<=1 ? "à l'instant" : mins+" min";
  const hrs = Math.floor(mins/60);
  if(hrs < 24) return hrs+" h";
  return Math.floor(hrs/24)+" j";
}

function renderNewsFeed(){
  const feed = document.getElementById('newsFeed');
  feed.innerHTML = '';
  state.posts.forEach(post=>{
    const liked = state.currentUser && post.likes.includes(state.currentUser.username);
    const el = document.createElement('div');
    el.className = 'news-post';
    el.innerHTML = `
      <div class="news-post-head">
        <div class="post-avatar">${post.author[0].toUpperCase()}</div>
        <div class="post-meta"><strong>Imelda's Sweet Event</strong><span>${timeAgo(post.date)}</span></div>
      </div>
      <h3>${escapeHtml(post.title)}</h3>
      <p class="body">${escapeHtml(post.body)}</p>
      ${post.media==='image' ? '<div class="post-media media-image">🖼️ Photo à venir</div>' : ''}
      ${post.media==='video' ? '<div class="post-media media-video">▶ Vidéo à venir</div>' : ''}
      <div class="post-actions">
        <button class="action-btn ${liked?'liked':''}" data-like="${post.id}">${liked?'❤️':'🤍'} <span>${post.likes.length}</span> J'aime</button>
        <button class="action-btn" data-toggle-comments="${post.id}">💬 <span>${post.comments.length}</span> Commentaires</button>
      </div>
      <div class="comments-wrap" id="comments-${post.id}">
        ${renderComments(post)}
        ${state.currentUser ? `
          <div class="comment-input-row">
            <input type="text" placeholder="Écrire un commentaire…" data-comment-input="${post.id}">
            <button data-send-comment="${post.id}">Envoyer</button>
          </div>` : `<p class="login-gate">Vous devez être <a data-open-login="1">connecté·e</a> pour commenter.</p>`}
      </div>
    `;
    feed.appendChild(el);
  });

  feed.querySelectorAll('[data-like]').forEach(btn=>btn.addEventListener('click', ()=>toggleLike(btn.dataset.like)));
  feed.querySelectorAll('[data-toggle-comments]').forEach(btn=>btn.addEventListener('click', ()=>{
    document.getElementById('comments-'+btn.dataset.toggleComments).classList.toggle('open');
  }));
  feed.querySelectorAll('[data-send-comment]').forEach(btn=>btn.addEventListener('click', ()=>sendComment(btn.dataset.sendComment)));
  feed.querySelectorAll('[data-comment-input]').forEach(inp=>inp.addEventListener('keydown', (e)=>{
    if(e.key==='Enter') sendComment(inp.dataset.commentInput);
  }));
  feed.querySelectorAll('[data-open-login]').forEach(a=>a.addEventListener('click', ()=>openAuthModal('login')));
  feed.querySelectorAll('[data-reply-to]').forEach(btn=>btn.addEventListener('click', ()=>{
    const row = btn.closest('.comment-item').querySelector('.reply-input-row');
    row.style.display = row.style.display==='flex' ? 'none' : 'flex';
  }));
  feed.querySelectorAll('[data-send-reply]').forEach(btn=>btn.addEventListener('click', ()=>{
    sendReply(btn.dataset.postId, btn.dataset.sendReply);
  }));
}

function renderComments(post){
  if(post.comments.length===0) return '';
  return post.comments.map(c=>`
    <div class="comment-item">
      <div class="comment-head"><span class="comment-avatar">${c.author[0].toUpperCase()}</span><strong>${escapeHtml(c.author)}</strong><span style="font-size:0.72rem; opacity:0.5;">· ${timeAgo(c.date)}</span></div>
      <p class="ctext">${escapeHtml(c.text)}</p>
      <div class="comment-tools">${state.currentUser ? `<button data-reply-to="${c.id}">Répondre</button>` : ''}</div>
      <div class="reply-input-row comment-input-row" style="display:none; margin-left:38px;">
        <input type="text" placeholder="Répondre à ${escapeHtml(c.author)}…" data-reply-input="${c.id}">
        <button data-post-id="${post.id}" data-send-reply="${c.id}">Envoyer</button>
      </div>
      ${c.replies && c.replies.length ? `<div class="replies">${c.replies.map(r=>`
        <div class="reply-item"><div class="comment-head"><span class="comment-avatar">${r.author[0].toUpperCase()}</span><strong>${escapeHtml(r.author)}</strong><span style="font-size:0.7rem; opacity:0.5;">· ${timeAgo(r.date)}</span></div><p class="ctext">${escapeHtml(r.text)}</p></div>
      `).join('')}</div>` : ''}
    </div>
  `).join('');
}

async function toggleLike(postId){
  if(!state.currentUser){ openAuthModal('login'); return; }
  const post = state.posts.find(p=>p.id===postId);
  const idx = post.likes.indexOf(state.currentUser.username);
  if(idx>-1) post.likes.splice(idx,1); else post.likes.push(state.currentUser.username);
  await persistPosts();
  renderNewsFeed();
  const wrap = document.getElementById('comments-'+postId);
  if(wrap) wrap.classList.add('open');
}
async function sendComment(postId){
  const input = document.querySelector(`[data-comment-input="${postId}"]`);
  const text = input.value.trim();
  if(!text) return;
  const post = state.posts.find(p=>p.id===postId);
  post.comments.push({id:cryptoId(), author:state.currentUser.username, text, date:Date.now(), replies:[]});
  await persistPosts();
  renderNewsFeed();
  document.getElementById('comments-'+postId).classList.add('open');
}
async function sendReply(postId, commentId){
  const input = document.querySelector(`[data-reply-input="${commentId}"]`);
  const text = input.value.trim();
  if(!text) return;
  const post = state.posts.find(p=>p.id===postId);
  const comment = post.comments.find(c=>c.id===commentId);
  comment.replies = comment.replies || [];
  comment.replies.push({id:cryptoId(), author:state.currentUser.username, text, date:Date.now()});
  await persistPosts();
  renderNewsFeed();
  document.getElementById('comments-'+postId).classList.add('open');
}
function escapeHtml(str){
  const d = document.createElement('div'); d.textContent = str; return d.innerHTML;
}

