const GALLERY_GRADIENTS = [
  'linear-gradient(160deg,#F3C9D4,#E8B4C4)', 'linear-gradient(160deg,#F1E2C4,#E8D3C0)',
  'linear-gradient(160deg,#DCE6D3,#C9D8E0)', 'linear-gradient(160deg,#E8D3C0,#F3C9D4)',
  'linear-gradient(160deg,#F1E2C4,#DCE6D3)', 'linear-gradient(160deg,#E8B4C4,#F1E2C4)',
  'linear-gradient(160deg,#DCE6D3,#F3C9D4)'
];
function renderGallery(){
  const grid = document.getElementById('galleryGrid');
  if(!grid) return;
  grid.innerHTML = state.site.gallery.map((g,i)=>{
    const bg = g.image ? `background-image:url('${g.image}'); background-size:cover; background-position:center;` : `background:${GALLERY_GRADIENTS[i % GALLERY_GRADIENTS.length]};`;
    return `<div class="g-item" style="${bg}"><span class="g-caption">${g.image ? escapeHtml(g.caption) : escapeHtml(g.caption)}</span></div>`;
  }).join('');
}

/* ---------------- SHOP / PRODUCTS ---------------- */
function renderProducts(filter){
  const grid = document.getElementById('productsGrid');
  grid.innerHTML = '';
  state.site.products.filter(p=> filter==='all' || p.cat===filter).forEach(p=>{
    const card = document.createElement('div');
    card.className = 'product-card';
    const imgStyle = p.image ? `style="background-image:url('${p.image}'); background-size:cover; background-position:center;"` : '';
    card.innerHTML = `
      <div class="product-img ${p.image ? '' : p.cls}" ${imgStyle}>${p.badge ? `<span class="badge">${p.badge}</span>` : ''}${p.image ? '' : 'Photo à venir'}</div>
      <div class="product-body">
        <span class="product-cat">${p.catLabel}</span>
        <h4>${p.name}</h4>
        <div class="product-foot">
          <span class="price">${p.price.toLocaleString('fr-FR')} FCFA</span>
          <button class="add-btn" data-id="${p.id}" data-add="${p.name}" data-price="${p.price}" data-image="${p.image||''}">+</button>
        </div>
      </div>`;
    grid.appendChild(card);
  });
  grid.querySelectorAll('[data-add]').forEach(btn=>btn.addEventListener('click', ()=>{
    addToCart({id:btn.dataset.id, name:btn.dataset.add, price:Number(btn.dataset.price), image:btn.dataset.image||null});
    btn.textContent='✓'; setTimeout(()=>btn.textContent='+', 800);
  }));
}
document.querySelectorAll('#filterTabs button').forEach(btn=>{
  btn.addEventListener('click', ()=>{
    document.querySelectorAll('#filterTabs button').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    renderProducts(btn.dataset.filter);
    initScrollReveal();
  });
});

/* ---------------- CART / CHECKOUT ---------------- */
function cartLineKey(item){ return item.id || item.name; }

function addToCart(item){
  const key = cartLineKey(item);
  const existing = cart.find(i=>cartLineKey(i)===key);
  if(existing){ existing.qty += 1; }
  else{ cart.push({id:item.id||null, name:item.name, price:item.price, image:item.image||null, qty:1}); }
  updateCartCount();
}
function updateCartCount(){
  document.getElementById('cartCount').textContent = cart.reduce((s,i)=>s+i.qty,0);
}
function cartTotal(){ return cart.reduce((s,i)=>s+(i.price*i.qty),0); }

function renderCartItems(){
  const list = document.getElementById('cartItemsList');
  if(cart.length===0){ list.innerHTML = '<p style="text-align:center; padding:20px 0; color:rgba(46,15,28,0.5); font-size:0.85rem;">Votre panier est vide.</p>'; }
  else{
    list.innerHTML = cart.map((i,idx)=>{
      const thumb = i.image
        ? `<img src="${i.image}" alt="${escapeHtml(i.name)}" class="cart-item-thumb">`
        : `<div class="cart-item-thumb placeholder">🎂</div>`;
      return `<div class="cart-item-row" data-idx="${idx}">
        ${thumb}
        <div class="cart-item-info">
          <span class="name">${escapeHtml(i.name)}</span>
          <span class="unit-price">${i.price.toLocaleString('fr-FR')} FCFA / unité</span>
        </div>
        <div class="cart-item-qty">
          <button type="button" class="qty-btn" data-qty-action="dec" data-idx="${idx}">−</button>
          <span class="qty-value">${i.qty}</span>
          <button type="button" class="qty-btn" data-qty-action="inc" data-idx="${idx}">+</button>
        </div>
        <span class="cart-item-total">${(i.price*i.qty).toLocaleString('fr-FR')} FCFA</span>
        <button type="button" class="cart-item-remove" data-remove-idx="${idx}" title="Retirer">✕</button>
      </div>`;
    }).join('');
  }
  document.getElementById('cartTotalRow').innerHTML = `<span>Total</span><span>${cartTotal().toLocaleString('fr-FR')} FCFA</span>`;

  list.querySelectorAll('[data-qty-action]').forEach(btn=>btn.addEventListener('click', ()=>{
    const idx = Number(btn.dataset.idx);
    if(btn.dataset.qtyAction==='inc'){ cart[idx].qty += 1; }
    else{ cart[idx].qty -= 1; if(cart[idx].qty<=0){ cart.splice(idx,1); } }
    updateCartCount();
    renderCartItems();
  }));
  list.querySelectorAll('[data-remove-idx]').forEach(btn=>btn.addEventListener('click', ()=>{
    cart.splice(Number(btn.dataset.removeIdx),1);
    updateCartCount();
    renderCartItems();
  }));
}

function renderPaymentMethods(){
  const wrap = document.getElementById('paymentMethods');
  wrap.innerHTML = PAYMENT_METHODS.map(m=>`
    <label class="payment-option ${selectedPayment===m.id ? 'selected' : ''}" data-pay-id="${m.id}">
      <input type="radio" name="paymentMethod" value="${m.id}" ${selectedPayment===m.id ? 'checked' : ''}>
      <span class="pay-logo ${m.cls}">${m.initials}</span>
      <span class="pay-name">${m.name}</span>
    </label>`).join('');
  wrap.querySelectorAll('.payment-option').forEach(opt=>opt.addEventListener('click', ()=>{
    selectedPayment = opt.dataset.payId;
    wrap.querySelectorAll('.payment-option').forEach(o=>o.classList.toggle('selected', o.dataset.payId===selectedPayment));
  }));
}

document.getElementById('cartBtn').addEventListener('click', ()=>{
  if(cart.length===0){ alert("Votre panier est vide. Ajoutez des produits depuis la boutique."); return; }
  renderCartItems();
  renderPaymentMethods();
  document.getElementById('checkoutModal').classList.add('open');
});
document.getElementById('closeCheckoutModal').addEventListener('click', ()=>document.getElementById('checkoutModal').classList.remove('open'));

function buildWhatsAppMessage(order){
  const payLabel = (PAYMENT_METHODS.find(m=>m.id===order.payment) || {}).name || order.payment;
  const lines = [
    `Bonjour Imelda's Sweet Event's, je souhaite passer la commande suivante :`,
    ``,
    ...order.items.map(i=>`• ${i.name} x${i.qty} — ${(i.price*i.qty).toLocaleString('fr-FR')} FCFA`),
    ``,
    `Total : ${order.total.toLocaleString('fr-FR')} FCFA`,
    `Moyen de paiement : ${payLabel}`,
    ``,
    `Nom : ${order.name}`,
    `Téléphone : ${order.phone}`,
    `Adresse de livraison : ${order.address}`
  ];
  return lines.join('\n');
}

document.getElementById('checkoutForm').addEventListener('submit', async (e)=>{
  e.preventDefault();
  if(cart.length===0){ document.getElementById('checkoutError').textContent = "Votre panier est vide."; return; }
  const order = {
    id:cryptoId(),
    name:document.getElementById('checkoutName').value,
    phone:document.getElementById('checkoutPhone').value,
    address:document.getElementById('checkoutAddress').value,
    items:cart.slice(),
    total:cartTotal(),
    payment:selectedPayment,
    date:Date.now(),
    user: state.currentUser ? state.currentUser.username : "Visiteur"
  };
  state.orders.push(order);
  await persistOrders();

  const waUrl = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(buildWhatsAppMessage(order))}`;
  window.open(waUrl, '_blank', 'noopener');

  document.getElementById('checkoutSuccess').style.display='block';
  cart = [];
  updateCartCount();
  setTimeout(()=>{ document.getElementById('checkoutModal').classList.remove('open'); document.getElementById('checkoutSuccess').style.display='none'; e.target.reset(); }, 1800);
});

