function renderDashboard(){
  if(!(state.currentUser && state.currentUser.role==='admin')) return;
  const now = Date.now();
  const onlineThreshold = 5*60*1000;
  document.getElementById('statUsers').textContent = state.users.length;
  document.getElementById('statOnline').textContent = state.users.filter(u=> now-(u.lastActive||0) < onlineThreshold).length;
  document.getElementById('statPosts').textContent = state.posts.length;
  document.getElementById('statOrders').textContent = state.orders.length;

  const table = document.getElementById('userTable');
  table.innerHTML = state.users.map(u=>{
    const online = now-(u.lastActive||0) < onlineThreshold;
    return `<div class="user-row">
      <div class="u-info">
        <span class="${online?'online-dot':'offline-dot'}"></span>
        <div><strong>${escapeHtml(u.username)}</strong><br><span style="font-size:0.78rem; opacity:0.6;">${escapeHtml(u.email||'')}</span></div>
        <span class="role-badge ${u.role==='client'?'client':''}">${u.role}</span>
      </div>
      <div class="row-actions">
        <button data-toggle-role="${u.username}">${u.role==='admin' ? 'Rétrograder' : 'Promouvoir admin'}</button>
        <button class="danger" data-delete-user="${u.username}">Supprimer</button>
      </div>
    </div>`;
  }).join('');
  table.querySelectorAll('[data-toggle-role]').forEach(btn=>btn.addEventListener('click', async ()=>{
    const u = state.users.find(x=>x.username===btn.dataset.toggleRole);
    u.role = u.role==='admin' ? 'client' : 'admin';
    await persistUsers(); renderDashboard();
  }));
  table.querySelectorAll('[data-delete-user]').forEach(btn=>btn.addEventListener('click', async ()=>{
    if(!confirm(`Supprimer le compte "${btn.dataset.deleteUser}" ?`)) return;
    state.users = state.users.filter(x=>x.username!==btn.dataset.deleteUser);
    await persistUsers(); renderDashboard();
  }));

  document.getElementById('editHeroTitle').value = document.getElementById('heroTitle').textContent.trim();
  document.getElementById('editHeroSubtitle').value = document.getElementById('heroSubtitle').textContent.trim();
  document.getElementById('colorBerry').value = state.site.colors.berry;
  document.getElementById('colorGold').value = state.site.colors.gold;
  document.getElementById('colorBlush').value = state.site.colors.blush;
  document.getElementById('colorInk').value = state.site.colors.ink;
  document.getElementById('logoPreview').src = (state.site.images && state.site.images.logo) || DEFAULT_LOGO_B64;

  renderProductEditList();
  renderGalleryEditList();

  const tList = document.getElementById('testimonialEditList');
  tList.innerHTML = state.site.testimonials.map((t,i)=>`
    <div class="testimonial-edit-row"><span>${escapeHtml(t.name)} — "${escapeHtml(t.text.slice(0,40))}…"</span><button data-del-testi="${i}" style="background:none;border:none;color:var(--berry);cursor:pointer;">✕</button></div>
  `).join('');
  tList.querySelectorAll('[data-del-testi]').forEach(btn=>btn.addEventListener('click', async ()=>{
    state.site.testimonials.splice(Number(btn.dataset.delTesti),1);
    await persistSite(); renderDashboard(); renderTestimonials();
  }));

  const newsList = document.getElementById('dashNewsList');
  newsList.innerHTML = state.posts.map(p=>`
    <div class="dash-news-row"><span>${escapeHtml(p.title)}</span><button data-del-post="${p.id}" style="background:none;border:none;color:var(--berry);cursor:pointer;">Supprimer</button></div>
  `).join('');
  newsList.querySelectorAll('[data-del-post]').forEach(btn=>btn.addEventListener('click', async ()=>{
    if(!confirm('Supprimer cette publication ?')) return;
    state.posts = state.posts.filter(p=>p.id!==btn.dataset.delPost);
    await persistPosts(); renderDashboard(); renderNewsFeed();
  }));

  const ordersTable = document.getElementById('ordersTable');
  ordersTable.innerHTML = state.orders.length ? state.orders.slice().reverse().map(o=>`
    <div class="user-row">
      <div class="u-info"><div><strong>${escapeHtml(o.name)}</strong><br><span style="font-size:0.78rem; opacity:0.6;">${escapeHtml(o.phone)} · ${o.items.length} article(s)</span></div></div>
      <span style="font-weight:700;">${o.total.toLocaleString('fr-FR')} FCFA</span>
    </div>`).join('') : '<p class="dash-hint">Aucune commande pour le moment.</p>';
}

/* ---------------- DASHBOARD: PHOTOS PRODUITS ---------------- */
function renderProductEditList(){
  const list = document.getElementById('productEditList');
  if(!list) return;
  list.innerHTML = state.site.products.map(p=>{
    const thumbStyle = p.image ? `background-image:url('${p.image}');` : '';
    return `
    <div class="image-edit-card" data-product="${p.id}">
      <div class="image-edit-thumb ${p.image ? '' : p.cls}" style="${thumbStyle}">${p.image ? '' : 'Photo à venir'}</div>
      <input type="text" data-field="name" value="${escapeHtml(p.name)}" placeholder="Nom du produit">
      <input type="number" data-field="price" value="${p.price}" placeholder="Prix (FCFA)">
      <input type="file" data-field="image" accept="image/*">
      <span class="img-save-note">✓ Enregistré</span>
    </div>`;
  }).join('');

  list.querySelectorAll('.image-edit-card').forEach(card=>{
    const id = card.dataset.product;
    const product = state.site.products.find(p=>p.id===id);
    const note = card.querySelector('.img-save-note');
    const flash = ()=>{ note.classList.add('show'); setTimeout(()=>note.classList.remove('show'), 1200); };

    card.querySelector('[data-field="name"]').addEventListener('change', async (e)=>{
      product.name = e.target.value.trim() || product.name;
      await persistSite(); renderProducts(document.querySelector('#filterTabs button.active').dataset.filter); flash();
    });
    card.querySelector('[data-field="price"]').addEventListener('change', async (e)=>{
      const val = Number(e.target.value);
      if(!isNaN(val) && val >= 0){ product.price = val; await persistSite(); renderProducts(document.querySelector('#filterTabs button.active').dataset.filter); flash(); }
    });
    card.querySelector('[data-field="image"]').addEventListener('change', async (e)=>{
      const file = e.target.files[0];
      if(!file) return;
      product.image = await fileToDataURL(file);
      await persistSite();
      renderProducts(document.querySelector('#filterTabs button.active').dataset.filter);
      renderProductEditList();
    });
  });
}

