/* ---------------- SCROLL REVEAL ---------------- */
let revealObserver = null;
function initScrollReveal(){
  const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const selectors = '.service-card, .product-card, .testimonial-card, .help-card, .value-item, .g-item, .stat-card, .info-block, .faq-item';
  const els = document.querySelectorAll(selectors);
  if(!revealObserver){
    revealObserver = new IntersectionObserver((entries)=>{
      entries.forEach(entry=>{
        if(entry.isIntersecting){
          entry.target.classList.add('visible');
          revealObserver.unobserve(entry.target);
        }
      });
    }, {threshold:0.15, rootMargin:'0px 0px -40px 0px'});
  }
  els.forEach((el, i)=>{
    if(el.dataset.revealed) return; // already wired up
    el.dataset.revealed = '1';
    el.classList.add('reveal');
    if(!reduceMotion){
      const groupIndex = i % 8; // stagger within a visible row/batch
      el.style.transitionDelay = (groupIndex * 0.07) + 's';
    }
    revealObserver.observe(el);
  });
}

/* ---------------- HERO 3D (Three.js) ---------------- */
function initHero3D(){
  const canvas = document.getElementById('hero3d');
  if(!canvas || typeof THREE === 'undefined') return;
  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(42, canvas.clientWidth/canvas.clientHeight, 0.1, 100);
  camera.position.set(0, 0.6, 6.2);
  const renderer = new THREE.WebGLRenderer({canvas, antialias:true, alpha:true});
  renderer.setSize(canvas.clientWidth, canvas.clientHeight);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));

  scene.add(new THREE.AmbientLight(0xffffff, 0.6));
  const light1 = new THREE.PointLight(0xffffff, 1.3); light1.position.set(4,5,5); scene.add(light1);
  const light2 = new THREE.PointLight(0xC4173D, 0.5); light2.position.set(-4,-2,3); scene.add(light2);

  const group = new THREE.Group();
  const tiers = [
    {r:1.5, h:0.6, color:0xC4173D},
    {r:1.1, h:0.55, color:0xF3C9D4},
    {r:0.72, h:0.5, color:0xB8892B}
  ];
  let y = -1.15;
  tiers.forEach(t=>{
    const geo = new THREE.CylinderGeometry(t.r, t.r, t.h, 48);
    const mat = new THREE.MeshStandardMaterial({color:t.color, roughness:0.35, metalness:0.18});
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.y = y + t.h/2;
    group.add(mesh);
    y += t.h;
  });
  const topGeo = new THREE.ConeGeometry(0.14, 0.45, 20);
  const topMat = new THREE.MeshStandardMaterial({color:0x2E0F1C, roughness:0.4});
  const top = new THREE.Mesh(topGeo, topMat);
  top.position.y = y + 0.22;
  group.add(top);
  scene.add(group);

  const sparkleGeo = new THREE.BufferGeometry();
  const count = 70;
  const pos = new Float32Array(count*3);
  for(let i=0;i<count;i++){
    pos[i*3] = (Math.random()-0.5)*6;
    pos[i*3+1] = (Math.random()-0.5)*4;
    pos[i*3+2] = (Math.random()-0.5)*3;
  }
  sparkleGeo.setAttribute('position', new THREE.BufferAttribute(pos,3));
  const sparkles = new THREE.Points(sparkleGeo, new THREE.PointsMaterial({color:0xB8892B, size:0.05}));
  scene.add(sparkles);

  const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  let mouseX = 0;
  window.addEventListener('mousemove', (e)=>{ mouseX = (e.clientX/window.innerWidth - 0.5); });

  function animate(){
    requestAnimationFrame(animate);
    if(!reduceMotion){
      group.rotation.y += 0.007;
      group.rotation.y += mouseX*0.002;
      sparkles.rotation.y -= 0.0015;
    }
    renderer.render(scene, camera);
  }
  animate();

  window.addEventListener('resize', ()=>{
    if(!canvas.clientWidth || !canvas.clientHeight) return;
    camera.aspect = canvas.clientWidth/canvas.clientHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(canvas.clientWidth, canvas.clientHeight);
  });
}

/* ---------------- INIT ---------------- */
async function init(){
  await loadAll();
  applySiteContent();
  renderTestimonials();
  renderProducts('all');
  renderGallery();
  renderNewsFeed();

  const session = await loadSession();
  if(session){
    const u = state.users.find(x=>x.username===session.username);
    if(u){ state.currentUser = {username:u.username, email:u.email, role:u.role}; u.lastActive = Date.now(); await persistUsers(); }
  }
  renderAuthArea();
  renderNewsFeed();
  initScrollReveal();

  initHero3D();
  hidePreloader();

  // heartbeat: keep lastActive fresh while browsing (for "online now" stat)
  setInterval(async ()=>{
    if(state.currentUser){
      const u = state.users.find(x=>x.username===state.currentUser.username);
      if(u){ u.lastActive = Date.now(); await persistUsers(); }
    }
  }, 60000);
}
init();
